import{_ as e,o as t,c as o,a}from"./app.f633e21d.js";const k=JSON.parse('{"title":"Wee786Harry v. lil_wayne, Jun 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/wee786harry_v_lil_wayne_jun_2018.md","lastUpdated":1666477380000}'),r={name:"government/court-cases-precedents/wee786harry_v_lil_wayne_jun_2018.md"},n=a('<h1 id="wee786harry-v-lil-wayne-jun-2018" tabindex="-1">Wee786Harry v. lil_wayne, Jun 2018 <a class="header-anchor" href="#wee786harry-v-lil-wayne-jun-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Oddish tacitly presiding, on 17th June 2018, Wee786Harry charged lil_wayne with Theft and Murder. lil_wayne was ordered to return all stolen items, and both parties were ordered to avoid each other.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>Wee786Harry</strong>:</p><blockquote><p>I wish to take lil_wayne to trial</p></blockquote><blockquote><p>He came to my house hit me and i had to defend</p></blockquote><blockquote><p>he killed me and took my s**t</p></blockquote><p><strong>lil_wayne</strong>:</p><blockquote><p>no he charged out of his house and attacked me after threatening to attack me in chat</p></blockquote><blockquote><p>i defended myself</p></blockquote><blockquote><p>i have witnesses</p></blockquote><blockquote><p>im willing to give it back if he says sorry</p></blockquote><p><strong>Wee786Harry</strong>:</p><blockquote><p>Can we take this to court, I am suing for 5 stacks of diamonds and all my stuff back including prot 4 and all my pots and gapples</p></blockquote><blockquote><p>[...these proceedings are cancer, read more at your own risk:</p></blockquote><blockquote><p><a href="https://discord.com/channels/278045721742147586/348687557455904778/457731110776864810" target="_blank" rel="noreferrer">https://discord.com/channels/278045721742147586/348687557455904778/457731110776864810</a>]</p></blockquote><p><strong>Oddish</strong>:</p><blockquote><p>right now the evidence thats presented shows that both sides have aggravated each other to some extent, the witnesses and known behaviour of weeharry raises some concerns as to the validity of this fight given that it was shown after both sides are potted and with pvp gear and have meet before. Although the video does show that the fight was started by thoths. However given the fact it is known harry is an agitator and that both sides have armour and pots prior to the fight starting I see no major reason of unjust fighting here. I do see two sides bickering and fighting against each other so I will like to make a decision to solve this.</p></blockquote><blockquote><p>lil_wayne, you are asked by the courts to not interact with weeharry and to leave him well alone, I do not want another fight and will consider this as a warning, Also to return any armour, pots or wepons taken from harry or the yoahtl pot bunker on the 16th of june</p></blockquote><blockquote><p>Wee786Harry, The court asks that you cease agitation to other residence and allies of Yoahtl to help prevent this from happening again. also this will be considered as a formal warning to you. any further cases will be taken into consideration for the government to make a decision as to have you remain as a resident.</p></blockquote>',21),s=[n];function i(h,l,c,d,p,u){return t(),o("div",null,s)}const _=e(r,[["render",i]]);export{k as __pageData,_ as default};
